    let num_workers = 4;
    let num_segments = 16;

    for worker_id in 0..num_workers {
        let segments_per_worker = num_segments / num_workers;
        let start = worker_id * segments_per_worker;
        let end = start + segments_per_worker;
        let segments: Vec<usize> = (start..end).collect();
        println!("Worker {}: {:?}", worker_id, segments);
    }
}
